const iterations = $.steps.fetchMessages.response.iterations || [];
let emailData = [];

iterations.forEach(iter => {
  const resp = iter.getMessage ? iter.getMessage.response : null;
  if (!resp) return;
  const headers = (resp.payload && resp.payload.headers) || [];
  const subject = (headers.find(h => h.name === 'Subject') || {}).value || '';
  const from = (headers.find(h => h.name === 'From') || {}).value || '';
  const date = (headers.find(h => h.name === 'Date') || {}).value || '';
  let body = '';
  if (resp.payload && resp.payload.body && resp.payload.body.data) {
    body = resp.payload.body.data;
  } else if (resp.payload && resp.payload.parts) {
    const textPart = resp.payload.parts.find(p => p.mimeType === 'text/plain');
    if (textPart && textPart.body && textPart.body.data) body = textPart.body.data;
  }
  if (body) {
    try { body = Buffer.from(body, 'base64').toString('utf-8'); } catch(e) { body = ''; }
  }
  emailData.push({ subject, from, date, body: body.slice(0, 2000) });
});

return { emailData, emailCount: emailData.length };

const emails = $.steps.extractEmailContent.output.emailData || [];
let emailsText = '';
emails.forEach((e, i) => {
  emailsText += '=== EMAIL ' + (i + 1) + ' ===
';
  emailsText += 'Subject: ' + e.subject + '
';
  emailsText += 'From: ' + e.from + '
';
  emailsText += 'Date: ' + e.date + '
';
  emailsText += 'Body:
' + e.body + '

';
});

const prompt = 'You are an expense data extraction specialist. Extract expense information from these emails.

' + emailsText + '
For each email that contains expense/receipt/invoice data, extract the details. Return ONLY valid JSON:
{
  "expenses": [
    {
      "date": "YYYY-MM-DD",
      "vendor": "vendor/merchant name",
      "description": "brief description of the expense",
      "category": "Food/Transport/Software/Office/Travel/Utilities/Other",
      "currency": "USD/EUR/GBP/etc",
      "amount": "numeric amount as string"
    }
  ],
  "totalExpenses": 0,
  "totalAmount": "0.00",
  "summary": "brief summary of expenses found"
}

If an email does not contain expense data, skip it. Be precise with amounts.';

return { prompt };

let raw = $.steps.aiExtract.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { expenses: [], totalExpenses: 0, summary: raw.slice(0, 200) }; }

const ai = $.steps.parseAI.output;
const expenses = ai.expenses || [];
const rows = expenses.map(e => [
  e.date || '',
  e.vendor || '',
  e.description || '',
  e.category || '',
  e.currency || 'USD',
  e.amount || '0'
]);
const slackText = 'Expense extraction complete: ' + expenses.length + ' expenses found. Total: ' + (ai.totalAmount || 'N/A') + '. ' + (ai.summary || '');
return { rows, slackText };
